    public static func ==(lhs: AuditEventInfo, rhs: AuditEventInfo) -> Bool {
        if lhs.id != rhs.id {
            return false
        }
        if lhs.timestamp != rhs.timestamp {
            return false
        }
        if lhs.workspaceId != rhs.workspaceId {
            return false
        }
        if lhs.panelId != rhs.panelId {
            return false
        }
        if lhs.eventType != rhs.eventType {
            return false
        }
        if lhs.severity != rhs.severity {
            return false
        }
        if lhs.description != rhs.description {
            return false
        }
        if lhs.metadataJson != rhs.metadataJson {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(id)
        hasher.combine(timestamp)
        hasher.combine(workspaceId)
        hasher.combine(panelId)
